// MapComponent.js
import React, { useEffect, useState } from "react";
import { MapContainer, TileLayer, CircleMarker, Popup } from "react-leaflet";
import "leaflet/dist/leaflet.css";
import BusTrendChart from "./BusTrendChart";

const MapComponent = () => {
  const [buses, setBuses] = useState([]);
  const [showChart, setShowChart] = useState(false);
  const [counts, setCounts] = useState({ normal: 0, ghost: 0, anomaly: 0 });

  const fetchBuses = async () => {
    try {
      const response = await fetch("http://127.0.0.1:8000/buses");
      const data = await response.json();
      setBuses(data);

      // Update counts
      const normalCount = data.filter((b) => b.status === "normal").length;
      const ghostCount = data.filter((b) => b.status === "ghost").length;
      const anomalyCount = data.filter((b) => b.status === "anomaly").length;
      setCounts({ normal: normalCount, ghost: ghostCount, anomaly: anomalyCount });
    } catch (err) {
      console.error("Error fetching buses:", err);
    }
  };

  useEffect(() => {
    fetchBuses();
    const interval = setInterval(fetchBuses, 120000); // fetch every 2 minutes
    return () => clearInterval(interval);
  }, []);

  const getColor = (status) => {
    if (status === "normal") return "green";
    if (status === "ghost") return "red";
    if (status === "anomaly") return "orange";
    return "blue";
  };

  return (
    <div style={{ position: "relative", width: "100%", height: "100vh" }}>
      {/* Toggle Button at top-left */}
      <button
        onClick={() => setShowChart(!showChart)}
        style={{
          position: "absolute",
          top: 10,
          left: 10,
          zIndex: 1000,
          padding: "8px 12px",
          backgroundColor: "#fff",
          border: "1px solid #ccc",
          borderRadius: "4px",
          cursor: "pointer",
        }}
      >
        {showChart ? "Hide Bus Chart" : "Show Bus Chart"}
      </button>

      {/* Floating Panel with Chart */}
      {showChart && (
        <div
          style={{
            position: "absolute",
            top: 50,
            left: 10,
            zIndex: 1000,
            width: 420,
            height: 320,
            backgroundColor: "#fff",
            padding: "10px",
            borderRadius: "8px",
            boxShadow: "0 4px 8px rgba(0,0,0,0.2)",
          }}
        >
          <BusTrendChart buses={buses} />
        </div>
      )}

      {/* Map */}
      <MapContainer
        center={[40.7128, -74.006]} // NYC center
        zoom={11}
        style={{ width: "100%", height: "100%" }}
        scrollWheelZoom={false}
      >
        <TileLayer
          url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
          attribution='&copy; <a href="http://osm.org/copyright">OpenStreetMap</a>'
        />

        {buses.map((bus) => (
          <CircleMarker
            key={bus.id + bus.timestamp} // ensure unique key
            center={[bus.lat, bus.lon]}
            radius={6}
            color={getColor(bus.status)}
          >
            <Popup>
              <div>
                <strong>ID:</strong> {bus.id} <br />
                <strong>Status:</strong> {bus.status}
              </div>
            </Popup>
          </CircleMarker>
        ))}
      </MapContainer>

      {/* Bus Counts at bottom-left */}
      <div
        style={{
          position: "absolute",
          bottom: 10,
          left: 10,
          zIndex: 1000,
          padding: "8px 12px",
          backgroundColor: "#fff",
          border: "1px solid #ccc",
          borderRadius: "4px",
        }}
      >
        Normal: {counts.normal} | Ghost: {counts.ghost} | Anomaly: {counts.anomaly}
      </div>
    </div>
  );
};

export default MapComponent;
